              gap: 40px;
            }
            
            .loan-card.blurred {
              filter: blur(4px);
              pointer-events: none;
              user-select: none;
              opacity: 0.7;
            }
            
            .logo {
              width: 60px;
              flex-shrink: 0;
            }
            
            .info-wrapper {
              display: flex;
              gap: 83px;
            }
            
            .info-block {
              display: flex;
              flex-direction: column;
              font-size: 14px;
              color: #1ebc62;
            }
            
            .info-block strong {
              color: #000;
              font-size: 18px;
              margin-top: 4px;
            }
            
            /* Overlay style */
            .card-overlay {
              position: absolute;
              top: 0;
              left: 0;
              width: 100%;
              height: 100%;
              background: rgba(255, 255, 255, 0.75);
              border-radius: 12px;
              display: flex;
              align-items: center;
              justify-content: center;
            }
            
            .lock-icon {
              width: 20px;
              height: 20px;
              opacity: 0.8;
            }

        </style>
